1	// Per-workout exercise prescription. References the exercise catalog by id;
2	// metadata (name, demo video, technique notes) lives in src/data/exerciseCatalog.ts.
3	export interface WorkoutExercise {
4	  exercise_id: string;
5	  sets: number;
6	  reps: string;
7	  rest: string;
8	  starting_weight?: number;
9	  weight_increment?: number;
10	  // Legacy-import fallback: when an imported program references an exercise
11	  // by name that does not map to a catalog entry, we keep the original name
12	  // here so the UI can still render it (without demos / technique cues).
13	  exercise_name?: string;
14	  from_legacy_import?: boolean;
15	}
16	
17	// Catalog-resolved exercise prepared for rendering. Merges catalog metadata
18	// with the workout's per-entry prescription (sets/reps/rest/weight defaults).
19	export interface ResolvedExercise {
20	  id: string;
21	  name: string;
22	  unmapped: boolean;
23	  sets: number;
24	  reps: string;
25	  rest: string;
